SELECT CHT.company_checkup_type_id , CCST.checkup_contract_sub_type_id , CCST.sub_type_name , H.hospital_id , H.hospital_name , H.hospital_center_name , H.center_id , H.center_name , R.reservation_id , R.reservation_state , R.hospital_pay , R.upgrade_pay , R.sum_item_copay , R.sum_item_discount_bill , R.state_notes , C.company_id , C.company_name , E.employee_name , E.employee_no , E.zipcode , E.address1 , E.address2 , E.depart , E.title , E.email , E.user_id , E.employee_code , E.birth , E.sex , E.mobile , EC.notes , CASE WHEN E.myself IS NULL THEN (SELECT employee_name FROM employee WHERE employee_code = E.employee_code AND employee.company_id = E.company_id AND myself = 1) END AS family_name , E.myself , CHT.company_checkup_type_code , CHT.company_checkup_type_name , EC.support_type , EC.vip , EC.special_checkup , IFNULL(EC.special_checkup_memo, '') AS special_checkup_memo , R.reservation_id , R.employee_notes , R.hospital_notes , R.platform_notes , R.registered_at , CASE R.reservation_state WHEN '1' THEN R.desired_at WHEN '3' THEN R.desired_at WHEN '5' THEN R.desired_at WHEN '2' THEN R.confirmed_at WHEN '4' THEN R.confirmed_at END AS desired_at , CASE R.reservation_state WHEN '1' THEN DATE_FORMAT(R.desired_at, '%p') WHEN '3' THEN DATE_FORMAT(R.desired_at, '%p') WHEN '5' THEN DATE_FORMAT(R.desired_at, '%p') WHEN '2' THEN DATE_FORMAT(R.confirmed_at, '%p') WHEN '4' THEN DATE_FORMAT(R.confirmed_at, '%p') END AS desired_ampm , R.confirmed_at , R.resulted_at , R.checkuped_at , DATE_FORMAT(R.checkuped_at, '%p') AS checkuped_ampm , R.confirmed_at , DATE_FORMAT(R.confirmed_at, '%p') AS confirmed_ampm , R.canceled_at , RI.reservation_id , RI.reservation_item_id , RI.checkup_contract_item_id , RI.register , RI.copay , RI.discount_bill , item.item_id , item.item_code , item.item_name , item.item_desc FROM reservation R JOIN reservation_item RI ON R.reservation_id = RI.reservation_id JOIN checkup_contract_item ON RI.checkup_contract_item_id = checkup_contract_item.checkup_contract_item_id JOIN item ON checkup_contract_item.item_id = item.item_id LEFT JOIN employee_checkup EC ON R.employee_checkup_id = EC.employee_checkup_id LEFT JOIN employee E ON EC.user_id = E.user_id JOIN company C ON E.company_id = C.company_id AND C.deleted_at IS NULL JOIN checkup_contract_sub_type CCST ON R.checkup_contract_sub_type_id = CCST.checkup_contract_sub_type_id LEFT JOIN checkup_contract_type CCT ON CCST.checkup_contract_type_id = CCT.checkup_contract_type_id LEFT JOIN company_checkup_type CHT ON CCT.company_checkup_type_id = CHT.company_checkup_type_id LEFT JOIN hospital_center_view H ON CCT.center_id = H.center_id WHERE E.deleted_at IS NULL AND EC.deleted_at IS NULL AND R.deleted_at IS NULL AND R.reservation_state != 0
AND R.registered_at >= #{reserveDateBegin} AND R.registered_at < DATE_ADD(#{reserveDateEnd}, INTERVAL 1 DAY)
AND R.desired_at >= #{reserveDateBegin} AND R.desired_at < DATE_ADD(#{reserveDateEnd}, INTERVAL 1 DAY)
AND C.company_id = #{companyId}
AND H.hospital_id = #{hospitalId}
AND H.center_id = #{centerId}
ORDER BY FIELD(reservation_state, '1', '3', '5', '2', '4') , (CASE reservation_state WHEN '1' THEN R.registered_at END) , (CASE reservation_state WHEN '3' THEN R.registered_at END) , (CASE reservation_state WHEN '5' THEN R.desired_at END) , (CASE reservation_state WHEN '2' THEN R.confirmed_at END) , (CASE reservation_state WHEN '4' THEN R.checkuped_at END) , employee_name DESC , RI.register

SELECT CHT.company_checkup_type_id , CCST.checkup_contract_sub_type_id , CCST.sub_type_name , H.hospital_id , H.hospital_name , H.hospital_center_name , H.center_id , H.center_name , R.reservation_id , R.reservation_state , R.hospital_pay , R.upgrade_pay , R.sum_item_copay , R.sum_item_discount_bill , R.state_notes , C.company_id , C.company_name , E.employee_name , E.employee_no , E.zipcode , E.address1 , E.address2 , E.depart , E.title , E.email , E.user_id , E.employee_code , E.birth , E.sex , E.mobile , EC.notes , CASE WHEN E.myself IS NULL THEN (SELECT employee_name FROM employee WHERE employee_code = E.employee_code AND employee.company_id = E.company_id AND myself = 1) END AS family_name , E.myself , CHT.company_checkup_type_code , CHT.company_checkup_type_name , EC.support_type , EC.vip , EC.special_checkup , IFNULL(EC.special_checkup_memo, '') AS special_checkup_memo , R.reservation_id , R.employee_notes , R.hospital_notes , R.platform_notes , R.registered_at , CASE R.reservation_state WHEN '1' THEN R.desired_at WHEN '3' THEN R.desired_at WHEN '5' THEN R.desired_at WHEN '2' THEN R.confirmed_at WHEN '4' THEN R.confirmed_at END AS desired_at , CASE R.reservation_state WHEN '1' THEN DATE_FORMAT(R.desired_at, '%p') WHEN '3' THEN DATE_FORMAT(R.desired_at, '%p') WHEN '5' THEN DATE_FORMAT(R.desired_at, '%p') WHEN '2' THEN DATE_FORMAT(R.confirmed_at, '%p') WHEN '4' THEN DATE_FORMAT(R.confirmed_at, '%p') END AS desired_ampm , R.confirmed_at , R.resulted_at , R.checkuped_at , DATE_FORMAT(R.checkuped_at, '%p') AS checkuped_ampm , R.confirmed_at , DATE_FORMAT(R.confirmed_at, '%p') AS confirmed_ampm , R.canceled_at , RI.reservation_id , RI.reservation_item_id , RI.checkup_contract_item_id , RI.register , RI.copay , RI.discount_bill , item.item_id , item.item_code , item.item_name , item.item_desc FROM reservation R JOIN reservation_item RI ON R.reservation_id = RI.reservation_id JOIN checkup_contract_item ON RI.checkup_contract_item_id = checkup_contract_item.checkup_contract_item_id JOIN item ON checkup_contract_item.item_id = item.item_id LEFT JOIN employee_checkup EC ON R.employee_checkup_id = EC.employee_checkup_id LEFT JOIN employee E ON EC.user_id = E.user_id JOIN company C ON E.company_id = C.company_id AND C.deleted_at IS NULL JOIN checkup_contract_sub_type CCST ON R.checkup_contract_sub_type_id = CCST.checkup_contract_sub_type_id LEFT JOIN checkup_contract_type CCT ON CCST.checkup_contract_type_id = CCT.checkup_contract_type_id LEFT JOIN company_checkup_type CHT ON CCT.company_checkup_type_id = CHT.company_checkup_type_id LEFT JOIN hospital_center_view H ON CCT.center_id = H.center_id LEFT JOIN center_manager_company CMC on C.company_id = CMC.company_id WHERE E.deleted_at IS NULL AND CMC.deleted_at IS NULL AND EC.deleted_at IS NULL AND R.deleted_at IS NULL AND CMC.user_id = #{sessionUserId} AND R.reservation_state != 0
AND R.registered_at >= #{reserveDateBegin} AND R.registered_at < DATE_ADD(#{reserveDateEnd}, INTERVAL 1 DAY)
AND R.desired_at >= #{reserveDateBegin} AND R.desired_at < DATE_ADD(#{reserveDateEnd}, INTERVAL 1 DAY)
AND C.company_id = #{companyId}
AND H.hospital_id = #{hospitalId}
AND H.center_id = #{centerId}
ORDER BY FIELD(reservation_state, '1', '3', '5', '2', '4') , (CASE reservation_state WHEN '1' THEN R.registered_at END) , (CASE reservation_state WHEN '3' THEN R.registered_at END) , (CASE reservation_state WHEN '5' THEN R.desired_at END) , (CASE reservation_state WHEN '2' THEN R.confirmed_at END) , (CASE reservation_state WHEN '4' THEN R.checkuped_at END) , employee_name DESC

SELECT CHT.company_checkup_type_id , CCST.checkup_contract_sub_type_id , CCST.sub_type_name , hospital_center_view.hospital_id , hospital_center_view.hospital_name , hospital_center_view.center_id , hospital_center_view.center_name , hospital_center_view.hospital_center_name , R.reservation_id , R.reservation_state , R.desired_at , DATE_FORMAT(R.desired_at, '%p') AS ampm , R.confirmed_at , C.company_id , C.company_name , E.employee_name , E.user_id , E.employee_code , E.birth , E.sex , E.mobile , CASE WHEN E.myself IS NULL THEN (SELECT employee_name FROM employee WHERE employee_code = E.employee_code AND employee.company_id = E.company_id AND myself = 1) END AS family_name , E.myself , CHT.company_checkup_type_code , CHT.company_checkup_type_name , EC.support_type , EC.vip , R.registered_at , R.canceled_at , R.canceled_user_id FROM reservation R LEFT JOIN employee_checkup EC ON R.employee_checkup_id = EC.employee_checkup_id LEFT JOIN employee E ON EC.user_id = E.user_id JOIN company C ON E.company_id = C.company_id AND C.deleted_at IS NULL JOIN checkup_contract_sub_type CCST ON R.checkup_contract_sub_type_id = CCST.checkup_contract_sub_type_id LEFT JOIN checkup_contract_type CCT ON CCST.checkup_contract_type_id = CCT.checkup_contract_type_id LEFT JOIN company_checkup_type CHT ON CCT.company_checkup_type_id = CHT.company_checkup_type_id LEFT JOIN hospital_center_view ON CCT.center_id = hospital_center_view.center_id WHERE E.deleted_at IS NULL AND EC.deleted_at IS NULL AND R.deleted_at IS NULL AND R.reservation_state = 0
AND R.registered_at >= #{reserveDateBegin} AND R.registered_at < DATE_ADD(#{reserveDateEnd}, INTERVAL 1 DAY)
AND R.desired_at >= #{reserveDateBegin} AND R.desired_at < DATE_ADD(#{reserveDateEnd}, INTERVAL 1 DAY)
AND C.company_id = #{companyId}
AND hospital_center_view.hospital_id = #{hospitalId}
ORDER BY canceled_at , canceled_at DESC

SELECT CHT.company_checkup_type_id , CCST.checkup_contract_sub_type_id , CCST.sub_type_name , H.hospital_id , H.hospital_name , H.hospital_center_name , H.center_id , H.center_name , R.reservation_id , R.reservation_state , R.hospital_pay , R.upgrade_pay , R.sum_item_copay , R.sum_item_discount_bill , R.state_notes , C.company_id , C.company_name , E.employee_name , E.employee_no , E.zipcode , E.address1 , E.address2 , E.depart , E.title , E.email , E.user_id , E.employee_code , E.birth , E.sex , E.mobile , EC.notes , CASE WHEN E.myself IS NULL THEN (SELECT employee_name FROM employee WHERE employee_code = E.employee_code AND employee.company_id = E.company_id AND myself = 1) END AS family_name , E.myself , CHT.company_checkup_type_code , CHT.company_checkup_type_name , EC.support_type , EC.vip , EC.special_checkup , IFNULL(EC.special_checkup_memo, '') AS special_checkup_memo , R.reservation_id , R.employee_notes , R.hospital_notes , R.platform_notes , R.registered_at , R.desired_at , DATE_FORMAT(R.desired_at, '%p') AS desired_ampm , R.confirmed_at , R.resulted_at , R.checkuped_at , DATE_FORMAT(R.checkuped_at, '%p') AS checkuped_ampm , R.confirmed_at , DATE_FORMAT(R.confirmed_at, '%p') AS confirmed_ampm , R.canceled_at , RI.reservation_id , RI.reservation_item_id , RI.checkup_contract_item_id , RI.register , RI.copay , RI.discount_bill , item.item_id , item.item_code , item.item_name , item.item_desc FROM reservation R JOIN reservation_item RI ON R.reservation_id = RI.reservation_id JOIN checkup_contract_item ON RI.checkup_contract_item_id = checkup_contract_item.checkup_contract_item_id JOIN item ON checkup_contract_item.item_id = item.item_id LEFT JOIN employee_checkup EC ON R.employee_checkup_id = EC.employee_checkup_id LEFT JOIN employee E ON EC.user_id = E.user_id JOIN company C ON E.company_id = C.company_id AND C.deleted_at IS NULL LEFT JOIN ( SELECT company_id , MAX(checkup_year) AS checkup_year FROM company_checkup WHERE deleted_at IS NULL GROUP BY company_id ) LAST_CC ON C.company_id = LAST_CC.company_id JOIN checkup_contract_sub_type CCST ON R.checkup_contract_sub_type_id = CCST.checkup_contract_sub_type_id LEFT JOIN checkup_contract_type CCT ON CCST.checkup_contract_type_id = CCT.checkup_contract_type_id LEFT JOIN company_checkup_type CHT ON CCT.company_checkup_type_id = CHT.company_checkup_type_id LEFT JOIN hospital_center_view H ON CCT.center_id = H.center_id WHERE E.deleted_at IS NULL AND EC.deleted_at IS NULL AND R.deleted_at IS NULL AND R.reservation_state != 0 AND C.company_id = #{companyId}
AND H.hospital_id = #{hospitalId}
AND R.registered_at >= #{reserveDateBegin} AND R.registered_at < DATE_ADD(#{reserveDateEnd}, INTERVAL 1 DAY)
AND R.desired_at >= #{reserveDateBegin} AND R.desired_at < DATE_ADD(#{reserveDateEnd}, INTERVAL 1 DAY)
ORDER BY FIELD(reservation_state, '1', '3', '5', '2', '4') , (CASE reservation_state WHEN '1' THEN R.registered_at END) , (CASE reservation_state WHEN '3' THEN R.registered_at END) , (CASE reservation_state WHEN '5' THEN R.desired_at END) , (CASE reservation_state WHEN '2' THEN R.confirmed_at END) , (CASE reservation_state WHEN '4' THEN R.checkuped_at END) , employee_name DESC

