UPDATE reservation SET updated_user_id = #{sessionUserId} , updated_at = NOW()
, reservation_state = #{reservationState}
, canceled_at = NOW() , confirmed_at = NOW() , canceled_user_id = #{sessionUserId}
, confirmed_at = NULL , checkuped_at = NULL , desired_at = DATE_ADD(DATE(#{desiredAt}), INTERVAL IF(#{desiredAmpm} = 'AM', 10, 14) HOUR)
, confirmed_at = DATE_ADD(DATE(#{desiredAt}), INTERVAL IF(#{desiredAmpm} = 'AM', 10, 14) HOUR) , checkuped_at = NULL
, confirmed_at = NULL , checkuped_at = NULL
, checkuped_at = DATE_ADD(DATE(#{checkupedAt}), INTERVAL IF(#{checkupedAmpm} = 'AM', 10, 14) HOUR)
, checkuped_at = NOW()
, confirmed_at = NULL , checkuped_at = NULL
WHERE reservation_id = #{reservationId}

UPDATE reservation
SET confirmed_at = NOW()
  , updated_user_id     = #{sessionUserId}
  , updated_at          = NOW()
WHERE reservation_id = #{reservationId}

